+    auto file{AutoFile{fsbridge::fopen(m_header_file_path, "rb+")}};
+    if (file.IsNull()) {
+        throw BlockTreeStoreError(strprintf("Unable to open file %s\n", fs::PathToString(m_header_file_path)));
