+static int64_t ReadHeaderFileDataEnd(AutoFile& file)
+{
+    int64_t data_end;
+    uint32_t checksum;
+    DataStream data;
+    file.seek(HEADER_FILE_DATA_END_POS, SEEK_SET);
+    file >> data_end;
+    data << data_end;
+    data << HEADER_FILE_DATA_END_POS;
