+    for (const auto& [file, info] : fileInfo) {
+        int64_t pos{CalculateBlockFilesPos(file)};
+        stream << BlockFileInfoWrapper{info};
+        stream << pos;
+        checksum = crc32c::Crc32c(UCharCast(stream.data()), block_file_entry_size);
