+static uint8_t constexpr LAST_BLOCK_TYPE_SIZE{sizeof(uint32_t)};
+static uint8_t constexpr BLOCK_FILE_INFO_WRAPPER_SIZE{36};
+static uint8_t constexpr DISK_BLOCK_INDEX_WRAPPER_SIZE{104};
+static size_t constexpr CHECKSUM_SIZE{sizeof(uint32_t)};
+static size_t constexpr FILE_POSITION_SIZE{sizeof(int64_t)};
