+
+static int64_t CalculateBlockFilesPos(int nFile)
+{
+    Assume(nFile >= 0);
+    return BLOCK_FILES_DATA_START_POS + nFile * (BLOCK_FILE_INFO_WRAPPER_SIZE + CHECKSUM_SIZE);
+}
